namespace sv_9bdf923a60b1498c92adacde9518b718.Services;

/// <summary>
/// Scoped service (per-circuit) that polls for low-stock alerts and notifies
/// all subscribed components via <see cref="OnAlertCountChanged"/>.
/// Because the timer fires on a thread-pool thread, subscribers must wrap
/// StateHasChanged in InvokeAsync.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private string _warehouseId = "";

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Raised whenever a new poll result arrives.
    /// Fires from a background thread — subscribers must use InvokeAsync.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulates a database query.
        return Task.FromResult(_random.Next(0, 16));
    }

    public void StartPolling(string warehouseId)
    {
        StopPolling();
        _warehouseId = warehouseId;
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    public void UpdateWarehouse(string warehouseId)
    {
        if (_warehouseId == warehouseId) return;
        // Restart polling for the new warehouse.
        StartPolling(warehouseId);
    }

    public void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on start, then every 10 s.
        await PollOnceAsync();

        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await PollOnceAsync();
            }
        }
        catch (OperationCanceledException) { /* expected on stop */ }
    }

    private async Task PollOnceAsync()
    {
        LatestLowStockCount = await GetLowStockCountAsync(_warehouseId);
        OnAlertCountChanged?.Invoke();
    }

    public void Dispose() => StopPolling();
}

