@* Interactive island embedded in the static MainLayout *@
@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@using sv_9bdf923a60b1498c92adacde9518b718.Services

<select class="form-select form-select-sm w-auto"
        value="@_selectedId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseInfo.Available)
    {
        <option value="@wh.Key">@wh.Value</option>
    }
</select>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private string _selectedId = "WH-001";

    protected override void OnParametersSet()
    {
        if (Warehouse is not null)
            _selectedId = Warehouse.WarehouseId;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString() ?? "WH-001";
        var name = WarehouseInfo.Available.GetValueOrDefault(id, "Unknown");

        var updated = new WarehouseInfo { WarehouseId = id, Name = name };

        // Push the new value to every [CascadingParameter] subscriber across
        // all render modes in this circuit.
        await WarehouseSource.NotifyChangedAsync(updated);
    }
}

@* Interactive badge that subscribes to the scoped alert service *@
@rendermode InteractiveServer
@implements IDisposable
@inject InventoryAlertService AlertService
@using sv_9bdf923a60b1498c92adacde9518b718.Services

@if (AlertService.LatestLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertService.LatestLowStockCount</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Timer fires from a background thread, so wrap in InvokeAsync.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

