+@code {
+    [CascadingParameter]
+    private WarehouseInfo? Warehouse { get; set; }
+
+    private string _selectedId = "WH-001";
+
+    protected override void OnParametersSet()
+    {
+        if (Warehouse is not null)
+            _selectedId = Warehouse.WarehouseId;
+    }
+
+    private async Task OnWarehouseChanged(ChangeEventArgs e)
+    {
+        var id = e.Value?.ToString() ?? "WH-001";
+        var name = WarehouseInfo.Available.GetValueOrDefault(id, "Unknown");
+
+        var updated = new WarehouseInfo { WarehouseId = id, Name = name };
+
+        // Push the new value to every [CascadingParameter] subscriber across
+        // all render modes in this circuit.
+        await WarehouseSource.NotifyChangedAsync(updated);
+    }
+}
+

