@* Interactive badge that subscribes to the scoped alert service *@
@rendermode InteractiveServer
@implements IDisposable
@inject InventoryAlertService AlertService
@using sv_9bdf923a60b1498c92adacde9518b718.Services

@if (AlertService.LatestLowStockCount > 0)
{
