@page "/dashboard"
@rendermode InteractiveServer
@implements IDisposable
@inject InventoryAlertService AlertService
@using sv_9bdf923a60b1498c92adacde9518b718.Services

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-4">@Warehouse?.Name (@Warehouse?.WarehouseId)</p>
    </div>
</div>

<div class="card mb-4" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text fs-1">
            @if (AlertService.LatestLowStockCount > 0)
            {
                <span class="text-danger fw-bold">@AlertService.LatestLowStockCount</span>
            }
            else
            {
                <span class="text-success">0</span>
            }
        </p>
        <p class="text-muted">Items below minimum level &middot; refreshes every 10 s</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private Action? _handler;
    private string _lastWarehouseId = "";

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    protected override void OnParametersSet()
    {
        var currentId = Warehouse?.WarehouseId ?? "WH-001";
        if (currentId != _lastWarehouseId)
        {
            _lastWarehouseId = currentId;
            // (Re)start polling for the selected warehouse.
            AlertService.StartPolling(currentId);
        }
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
        AlertService.StopPolling();
    }
}

